
CREATE TABLE users (id BIGINT PRIMARY KEY, nom VARCHAR(100), prenom VARCHAR(100), phone VARCHAR(20) UNIQUE, email VARCHAR(100) NULL, commune VARCHAR(100), password VARCHAR(255), code_perso VARCHAR(10) UNIQUE, code_parrain VARCHAR(10) NULL, device_id VARCHAR(100) NULL, points INT DEFAULT 0, solde INT DEFAULT 0, niveau ENUM('Bronze','Argent','Or','Platine','Diamant','Ambassadeur') DEFAULT 'Bronze', filleuls_count INT DEFAULT 0, is_active BOOLEAN DEFAULT 0, otp_verified_at TIMESTAMP NULL, created_at TIMESTAMP, updated_at TIMESTAMP);
CREATE TABLE otps (id BIGINT PRIMARY KEY, phone VARCHAR(20), code VARCHAR(6), expires_at TIMESTAMP, created_at TIMESTAMP, updated_at TIMESTAMP);
CREATE TABLE referrals (id BIGINT PRIMARY KEY, parrain_id BIGINT, filleul_id BIGINT, status ENUM('pending','active') DEFAULT 'pending', created_at TIMESTAMP, updated_at TIMESTAMP, UNIQUE(parrain_id,filleul_id));
CREATE TABLE transactions (id BIGINT PRIMARY KEY, user_id BIGINT, type ENUM('welcome','referral','share','withdrawal','bonus_level'), points INT DEFAULT 0, amount INT DEFAULT 0, description VARCHAR(255), status ENUM('pending','completed','rejected') DEFAULT 'completed', created_at TIMESTAMP, updated_at TIMESTAMP);
CREATE TABLE withdrawals (id BIGINT PRIMARY KEY, user_id BIGINT, montant INT, operateur ENUM('Orange','MTN','Moov','Wave'), numero VARCHAR(20), status ENUM('pending','approved','rejected') DEFAULT 'pending', motif_rejet TEXT NULL, created_at TIMESTAMP, updated_at TIMESTAMP);
